        { num: 3, url: 'https://thethirdgalleryaya.com/artists/%E5%B2%A9%E5%AE%AE%E6%AD%A6%E4%BA%8C/', name: '岩宮武二 | Artists — The Third Gallery Aya' },
        { num: 4, url: 'https://fujifilmsquare.jp/activityreport/pack/pdf/activity_report_2019.pdf', name: '2019年度 活動報告書 — FUJIFILM SQUARE' }
